const ITEM_TYPE_PREMIUMS: Record<string, number> = {
  Sword: 50,
  Amulet: 100,
  Staff: 75,
  Potion: 60,
};

const FIRST_INSURANCE_SURCHARGE = 1.1;

export interface Item {
  type: string;
  insuranceModifier?: string;
}

const applyInsuranceModifier = (premium: number, modifier?: string): number => {
  if (modifier === "first") {
    return premium * FIRST_INSURANCE_SURCHARGE;
  }
  return premium;
};

export function quotePolicy(items: Item[]): number {
  const total = items.reduce((sum, item) => {
    const basePremium = ITEM_TYPE_PREMIUMS[item.type] ?? 0;
    const modifiedPremium = applyInsuranceModifier(basePremium, item.insuranceModifier);
    return sum + modifiedPremium;
  }, 0);
  return Math.round(total);
}
